//geometry-utils.js

import { Registry } from '../core/zc-registry';
import { mathCos, mathSin, mathPI } from '../core/zc-constants';
import { isArray } from './zcutils';
import { euclideanDistance as dist } from './geometry/_point';

import { outerTangentPoints$Circle } from './geometry/tangent-circle';
import { tangentPoints$Polygon } from './geometry/tangent-polygon';

export var geometryUtils = (function() {
    var rotatePoint = function(point, theta, origin = { x: 0, y: 0 }) {
            /* If you rotate point (px, py) around point (ox, oy) by angle theta you'll get:
			p'x = (px-ox) * cos(theta) + (py-oy) * sin(theta) + ox
			p'y = (px-ox) * sin(theta) - (py-oy) * cos(theta) + oy */

            var px = point.x,
                py = point.y,
                ox = origin.x,
                oy = origin.y;

            return {
                x: (px - ox) * mathCos(theta) + (py - oy) * mathSin(theta) + ox,
                y: (px - ox) * mathSin(theta) - (py - oy) * mathCos(theta) + oy
            };
        },
        pointInRectangle = function(point, rectangle) {
            var x1 = rectangle.x || 0,
                y1 = rectangle.y || 0,
                x2 = x1 + rectangle.width,
                y2 = y1 + rectangle.height,
                x,
                y;

            if (isArray(point)) {
                x = point[0];
                y = point[1];
            } else {
                x = point.x;
                y = point.y;
            }

            return x1 <= x && x <= x2 && (y1 <= y && y <= y2);
        },
        degreeToRadian = function(degree) {
            return (degree / 180) * mathPI;
        },
        areaOfEllipse = function(a, b) {
            return mathPI * a * b;
        },
        areaOfCircle = function(r) {
            return mathPI * r * r;
        },
        areaOfRect = function(w, h) {
            return w * h;
        };

    return {
        rotatePoint,
        pointInRectangle,
        degreeToRadian,
        areaOfEllipse,
        areaOfCircle,
        areaOfRect,
        dist,
        outerTangentPoints$Circle,
        tangentPoints$Polygon
    };
})();

// Returns true if two rectangles rect1 and rect2 overlap
export function doOverlap(rect1, rect2) {
    return !(rect1.x1 > rect2.x2 || rect2.x1 > rect1.x2 || rect1.y1 > rect2.y2 || rect2.y1 > rect1.y2);
}
Registry.setComponent('geometryUtils.doOverlapRect', doOverlap);
